INSERT INTO categories (id, name, description) VALUES
('cat-ml-foundations', 'ML Foundations', 'Core concepts that explain how machine learning models learn from data.'),
('cat-llm-concepts', 'LLM Concepts', 'Important ideas for understanding large language model behavior and usage.'),
('cat-inference-serving', 'Inference & Serving', 'How trained models are run, exposed, and optimized in applications.'),
('cat-data-training', 'Data & Training', 'Data-centric and optimization concepts used to train reliable AI systems.'),
('cat-ai-safety', 'AI Safety', 'Concepts for safer model behavior, risk management, and responsible usage.')
ON CONFLICT (id) DO UPDATE SET
    name = EXCLUDED.name,
    description = EXCLUDED.description;

INSERT INTO terms (
    id,
    slug,
    term,
    definition,
    explanation,
    humor,
    controversy_level,
    short_definition,
    full_explanation,
    category_id,
    tags,
    related_terms,
    example_usage,
    source,
    created_at,
    updated_at
) VALUES
('term-transformer', 'transformer', 'Transformer', 'A Transformer is a neural network architecture built around self-attention.', 'Transformer models process tokens in parallel and use stacked attention layers to model long-range relationships. They scale efficiently with compute and data, which is why they power most modern language models.', 'It replaced recurrence with attention and replaced "maybe later" with "ship it now."', 0, 'A Transformer is a neural network architecture built around self-attention.', 'Transformer models process tokens in parallel and use stacked attention layers to model long-range relationships. They scale efficiently with compute and data, which is why they power most modern language models.', 'cat-ml-foundations', 'architecture,attention,neural-networks,transformers', 'term-attention,term-token', 'Most production LLMs today are Transformer variants.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-attention', 'attention-mechanism', 'Attention Mechanism', 'An attention mechanism scores which tokens matter most for the current prediction.', 'Attention computes relevance weights between tokens so the model can focus on useful context instead of treating every token equally. Self-attention applies this process within one sequence.', 'Like inviting only the people who read the doc, not the whole org chart.', 0, 'An attention mechanism scores which tokens matter most for the current prediction.', 'Attention computes relevance weights between tokens so the model can focus on useful context instead of treating every token equally. Self-attention applies this process within one sequence.', 'cat-ml-foundations', 'attention,context,modeling,transformers', 'term-transformer,term-token', 'Attention helps connect words that are far apart in a sentence.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-token', 'token', 'Token', 'A token is the basic text unit an LLM reads and generates.', 'Tokenizers split text into vocabulary units before inference or training. Token counts drive context usage, generation limits, runtime, and cost.', 'Smallest unit of text, largest unit of billing surprise.', 0, 'A token is the basic text unit an LLM reads and generates.', 'Tokenizers split text into vocabulary units before inference or training. Token counts drive context usage, generation limits, runtime, and cost.', 'cat-llm-concepts', 'context-windows,llms,tokenization,tokens', 'term-context-window,term-transformer', 'Prompt limits are measured in tokens, not characters.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-context-window', 'context-window', 'Context Window', 'A context window is the maximum number of tokens a model can consider at once.', 'The context window must hold both prompt and generated output tokens. If the conversation exceeds the limit, systems must truncate, summarize, or retrieve supporting context.', 'It remembers a lot, right up until it absolutely does not.', 0, 'A context window is the maximum number of tokens a model can consider at once.', 'The context window must hold both prompt and generated output tokens. If the conversation exceeds the limit, systems must truncate, summarize, or retrieve supporting context.', 'cat-llm-concepts', 'context-management,context-windows,llms,tokens', 'term-token,term-rag', 'Long chats often require summarization once context windows fill up.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-rag', 'retrieval-augmented-generation-rag', 'Retrieval-Augmented Generation (RAG)', 'RAG is a pattern that retrieves external information before generation.', 'A RAG pipeline embeds and indexes documents, retrieves relevant passages for a query, then injects those passages into model context. This improves factual grounding and freshness without full model retraining.', 'Before answering with confidence, it checks the receipts.', 1, 'RAG is a pattern that retrieves external information before generation.', 'A RAG pipeline embeds and indexes documents, retrieves relevant passages for a query, then injects those passages into model context. This improves factual grounding and freshness without full model retraining.', 'cat-llm-concepts', 'grounding,llms,rag,retrieval', 'term-embedding,term-vector-database', 'Support assistants use RAG to answer product questions from docs.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-embedding', 'embedding', 'Embedding', 'An embedding is a dense vector that represents semantic meaning.', 'Embeddings map text or other data into numeric space so semantically similar items are close together. They are the backbone of semantic search, recommendation, and retrieval workflows.', 'Meaning, flattened into coordinates and still somehow useful.', 0, 'An embedding is a dense vector that represents semantic meaning.', 'Embeddings map text or other data into numeric space so semantically similar items are close together. They are the backbone of semantic search, recommendation, and retrieval workflows.', 'cat-data-training', 'embeddings,semantic-search,vectors', 'term-vector-database,term-rag', 'Similar user questions should map to nearby embedding vectors.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-vector-database', 'vector-database', 'Vector Database', 'A vector database stores and searches embeddings by similarity.', 'Vector databases build ANN (approximate nearest neighbor) indexes to return relevant vectors quickly at scale. They are commonly used as the retrieval store in RAG systems.', 'A database for vibes, except the vibes are cosine distance.', 0, 'A vector database stores and searches embeddings by similarity.', 'Vector databases build ANN (approximate nearest neighbor) indexes to return relevant vectors quickly at scale. They are commonly used as the retrieval store in RAG systems.', 'cat-inference-serving', 'databases,rag,retrieval,vector-search', 'term-embedding,term-rag', 'A vector DB can return top-k relevant chunks in milliseconds.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-inference', 'inference', 'Inference', 'Inference is running a trained model to produce outputs.', 'Inference happens after training and can run in online or batch systems. Runtime performance depends on model size, hardware, serving design, and precision choices.', 'The phase where the expensive model finally has to earn rent.', 0, 'Inference is running a trained model to produce outputs.', 'Inference happens after training and can run in online or batch systems. Runtime performance depends on model size, hardware, serving design, and precision choices.', 'cat-inference-serving', 'inference,latency,serving', 'term-quantization,term-latency', 'Every chat response token is produced during inference.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-quantization', 'quantization', 'Quantization', 'Quantization reduces numeric precision to make models cheaper to run.', 'Quantization converts model weights and sometimes activations to lower-bit formats such as INT8 or INT4. This often cuts memory footprint and latency, with some possible quality tradeoffs.', 'Teaching a model to travel light without losing its passport.', 1, 'Quantization reduces numeric precision to make models cheaper to run.', 'Quantization converts model weights and sometimes activations to lower-bit formats such as INT8 or INT4. This often cuts memory footprint and latency, with some possible quality tradeoffs.', 'cat-inference-serving', 'model-optimization,quantization,serving', 'term-inference,term-latency', 'INT8 quantization often enables larger models on smaller GPUs.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-latency', 'latency', 'Latency', 'Latency is the elapsed time between request and response.', 'In AI applications, latency includes network hops, retrieval time, queueing, and generation speed. Teams optimize it because lower latency improves user trust and task completion.', 'That awkward pause where users wonder if your app crashed.', 0, 'Latency is the elapsed time between request and response.', 'In AI applications, latency includes network hops, retrieval time, queueing, and generation speed. Teams optimize it because lower latency improves user trust and task completion.', 'cat-inference-serving', 'latency,performance,user-experience', 'term-inference,term-quantization', 'Token streaming can reduce perceived latency even if total latency is unchanged.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-fine-tuning', 'fine-tuning', 'Fine-tuning', 'Fine-tuning is additional training on task-specific data.', 'Fine-tuning adapts a general model to a narrower domain, style, or workflow. It can improve quality for specific tasks, but requires careful dataset curation, evaluation, and safety checks.', 'Taking a model with broad hobbies and giving it a full-time job.', 1, 'Fine-tuning is additional training on task-specific data.', 'Fine-tuning adapts a general model to a narrower domain, style, or workflow. It can improve quality for specific tasks, but requires careful dataset curation, evaluation, and safety checks.', 'cat-data-training', 'adaptation,fine-tuning,training', 'term-overfitting,term-evaluation', 'A legal assistant model may be fine-tuned on statute-style language.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-overfitting', 'overfitting', 'Overfitting', 'Overfitting is when a model memorizes training data and generalizes poorly.', 'An overfit model performs well on seen examples but fails on unseen data because it learned narrow patterns or noise. Validation splits, regularization, and data diversity help prevent it.', 'Perfect score on homework, panic attack on the final exam.', 0, 'Overfitting is when a model memorizes training data and generalizes poorly.', 'An overfit model performs well on seen examples but fails on unseen data because it learned narrow patterns or noise. Validation splits, regularization, and data diversity help prevent it.', 'cat-data-training', 'evaluation,generalization,overfitting,training', 'term-fine-tuning,term-evaluation', 'High training accuracy with weak test accuracy is a classic overfitting sign.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-evaluation', 'model-evaluation', 'Model Evaluation', 'Model evaluation measures quality with defined tests and metrics.', 'Evaluation combines offline benchmarks, regression suites, and scenario-based assessments to measure capability, reliability, and safety before and after release changes.', 'Where confidence meets a scoreboard and negotiates terms.', 0, 'Model evaluation measures quality with defined tests and metrics.', 'Evaluation combines offline benchmarks, regression suites, and scenario-based assessments to measure capability, reliability, and safety before and after release changes.', 'cat-data-training', 'benchmarks,evaluation,metrics,quality', 'term-overfitting,term-hallucination', 'Teams rerun evaluation suites before shipping a new model snapshot.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-hallucination', 'hallucination', 'Hallucination', 'A hallucination is confident model output that is incorrect or unsupported.', 'Hallucinations occur when generated claims are not grounded in reliable evidence. Teams reduce risk with retrieval, constrained prompting, citations, and human review in high-stakes flows.', 'Saying it boldly does not make it true, but models still try.', 2, 'A hallucination is confident model output that is incorrect or unsupported.', 'Hallucinations occur when generated claims are not grounded in reliable evidence. Teams reduce risk with retrieval, constrained prompting, citations, and human review in high-stakes flows.', 'cat-ai-safety', 'factuality,grounding,hallucinations,reliability', 'term-rag,term-evaluation', 'Medical and legal assistants need strict hallucination mitigation strategies.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-guardrails', 'guardrails', 'Guardrails', 'Guardrails are controls that limit unsafe or off-policy model behavior.', 'Guardrails include policy classifiers, system instructions, output validators, moderation filters, and business-rule checks layered around model calls.', 'Seatbelts for your model before it drives into production traffic.', 1, 'Guardrails are controls that limit unsafe or off-policy model behavior.', 'Guardrails include policy classifiers, system instructions, output validators, moderation filters, and business-rule checks layered around model calls.', 'cat-ai-safety', 'guardrails,moderation,policy,safety', 'term-hallucination,term-red-teaming', 'A safety pipeline can block disallowed content before response delivery.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z'),
('term-red-teaming', 'red-teaming', 'Red Teaming', 'Red teaming is structured adversarial testing for model weaknesses.', 'Teams simulate harmful, tricky, and edge-case prompts to uncover failures in safety, robustness, and policy compliance. Findings feed guardrail improvements and evaluation updates.', 'Paying experts to break it before the internet does it for free.', 1, 'Red teaming is structured adversarial testing for model weaknesses.', 'Teams simulate harmful, tricky, and edge-case prompts to uncover failures in safety, robustness, and policy compliance. Findings feed guardrail improvements and evaluation updates.', 'cat-ai-safety', 'adversarial-testing,red-teaming,robustness,safety', 'term-guardrails,term-evaluation', 'Red-team exercises often run before major model launches.', 'Internal glossary seed', '2026-01-01T00:00:00Z', '2026-01-01T00:00:00Z')
ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    term = EXCLUDED.term,
    definition = EXCLUDED.definition,
    explanation = EXCLUDED.explanation,
    humor = EXCLUDED.humor,
    controversy_level = EXCLUDED.controversy_level,
    short_definition = EXCLUDED.short_definition,
    full_explanation = EXCLUDED.full_explanation,
    category_id = EXCLUDED.category_id,
    tags = EXCLUDED.tags,
    related_terms = EXCLUDED.related_terms,
    example_usage = EXCLUDED.example_usage,
    source = EXCLUDED.source,
    created_at = EXCLUDED.created_at,
    updated_at = EXCLUDED.updated_at;

