-- Curriculum-aligned glossary expansion (2026-05-25): the load-bearing terms
-- introduced by Units 1-15 of the "LLM Systems for PMs" path that the original
-- 16-term seed did not yet cover. Static authored content; rendered as inert
-- text by the app. Reuses the existing five categories.
INSERT INTO terms (
    id, slug, term, definition, explanation, humor, controversy_level,
    short_definition, full_explanation, category_id, tags, related_terms,
    example_usage, source, created_at, updated_at
) VALUES
('term-bpe', 'byte-pair-encoding-bpe', 'Byte-Pair Encoding (BPE)', 'BPE is a subword tokenization method that merges frequent character pairs into reusable tokens.', 'BPE starts from characters and repeatedly merges the most common adjacent pairs, so common words become single tokens while rare words split into pieces. It is why token counts do not match word or character counts.', 'It chops your text into pieces nobody asked for but everybody pays for.', 0, 'BPE is a subword tokenization method that merges frequent character pairs into reusable tokens.', 'BPE starts from characters and repeatedly merges the most common adjacent pairs, so common words become single tokens while rare words split into pieces. It is why token counts do not match word or character counts.', 'cat-llm-concepts', 'tokenization,bpe,subword,tokens', 'term-token,term-context-window', 'A rare technical term may cost several tokens under BPE while "the" costs one.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-cost-per-token', 'cost-per-token', 'Cost per Token', 'Cost per token is the per-unit price an LLM provider charges for input and output tokens.', 'Providers bill separately for input (prompt) and output (generated) tokens, usually at different rates. Reasoning about spend in tokens, not words or requests, is the foundation of LLM cost estimation.', 'The meter is always running, even when the model is just thinking.', 0, 'Cost per token is the per-unit price an LLM provider charges for input and output tokens.', 'Providers bill separately for input (prompt) and output (generated) tokens, usually at different rates. Reasoning about spend in tokens, not words or requests, is the foundation of LLM cost estimation.', 'cat-inference-serving', 'cost,tokens,pricing,economics', 'term-token,term-prompt-caching', 'Annualized spend is estimated from cost per token times projected token volume.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-system-prompt', 'system-prompt', 'System Prompt', 'A system prompt is the instruction block that sets a model''s role and rules, separate from user input.', 'The system turn carries durable behavior and policy; the user turn carries the request. Keeping instructions in the system turn and untrusted text in the user turn is a core trust-boundary practice.', 'The model''s job description, written in the hope it reads it.', 0, 'A system prompt is the instruction block that sets a model''s role and rules, separate from user input.', 'The system turn carries durable behavior and policy; the user turn carries the request. Keeping instructions in the system turn and untrusted text in the user turn is a core trust-boundary practice.', 'cat-llm-concepts', 'prompting,system-prompt,instructions', 'term-prompt-design,term-prompt-injection', 'Grading rules live in the system prompt; the learner answer goes in the user turn.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-prompt-design', 'prompt-design', 'Prompt Design', 'Prompt design is the practice of structuring instructions and examples to steer model behavior.', 'It covers system-versus-user roles, instruction clarity, and example selection. Prompts are model-specific in subtle ways, so design is empirical, not one-size-fits-all.', 'Half engineering, half wording the wish so the genie cannot misread it.', 0, 'Prompt design is the practice of structuring instructions and examples to steer model behavior.', 'It covers system-versus-user roles, instruction clarity, and example selection. Prompts are model-specific in subtle ways, so design is empirical, not one-size-fits-all.', 'cat-llm-concepts', 'prompting,prompt-design,instructions', 'term-system-prompt,term-few-shot', 'Switching providers often means re-tuning prompts that worked elsewhere.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-few-shot', 'few-shot-prompting', 'Few-shot Prompting', 'Few-shot prompting includes a handful of worked examples in the prompt to guide the output.', 'Examples demonstrate the desired format and reasoning without any retraining. It trades extra prompt tokens for more reliable, consistent behavior on a task.', 'Show, do not tell, then pay for the showing in tokens.', 0, 'Few-shot prompting includes a handful of worked examples in the prompt to guide the output.', 'Examples demonstrate the desired format and reasoning without any retraining. It trades extra prompt tokens for more reliable, consistent behavior on a task.', 'cat-llm-concepts', 'prompting,few-shot,examples', 'term-zero-shot,term-prompt-design', 'A few labeled examples can sharply improve classification consistency.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-zero-shot', 'zero-shot-prompting', 'Zero-shot Prompting', 'Zero-shot prompting asks the model to perform a task with instructions only and no examples.', 'It keeps prompts short and cheap and relies on the model''s general capability. It is the baseline to beat before spending tokens on few-shot examples.', 'Throwing the model into the deep end with only a pep talk.', 0, 'Zero-shot prompting asks the model to perform a task with instructions only and no examples.', 'It keeps prompts short and cheap and relies on the model''s general capability. It is the baseline to beat before spending tokens on few-shot examples.', 'cat-llm-concepts', 'prompting,zero-shot,instructions', 'term-few-shot,term-prompt-design', 'Capable models often handle simple tasks zero-shot, no examples needed.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-model-selection', 'model-selection', 'Model Selection', 'Model selection is choosing a model by weighing the capability, cost, and latency triangle against an eval.', 'Bigger models are more capable but slower and pricier; smaller models are cheaper and faster but weaker. The right pick is the cheapest, fastest model that still passes your evaluation bar.', 'Pick two of capable, cheap, fast, then explain to finance why.', 1, 'Model selection is choosing a model by weighing the capability, cost, and latency triangle against an eval.', 'Bigger models are more capable but slower and pricier; smaller models are cheaper and faster but weaker. The right pick is the cheapest, fastest model that still passes your evaluation bar.', 'cat-llm-concepts', 'model-selection,cost,latency,capability', 'term-latency,term-evaluation', 'A vendor bake-off compares models on the same eval before committing.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-llm-as-judge', 'llm-as-judge', 'LLM-as-Judge', 'LLM-as-judge uses a model to grade other models'' outputs against a rubric.', 'It scales evaluation beyond hand-grading but inherits model biases and needs its own calibration against human labels. It is one eval method among human review, golden sets, and live A/B.', 'Letting the fox grade the henhouse, but with a rubric and a straight face.', 2, 'LLM-as-judge uses a model to grade other models'' outputs against a rubric.', 'It scales evaluation beyond hand-grading but inherits model biases and needs its own calibration against human labels. It is one eval method among human review, golden sets, and live A/B.', 'cat-data-training', 'evaluation,llm-as-judge,grading', 'term-evaluation,term-golden-set', 'A grader model can score answers against criteria, then humans audit a sample.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-golden-set', 'golden-set', 'Golden Set', 'A golden set is a curated, labeled set of cases used as a fixed evaluation benchmark.', 'It encodes known-correct answers so changes can be measured against a stable bar. Re-running it after every change is how teams catch quality regressions.', 'The answer key you guard like it pays your rent, because it does.', 0, 'A golden set is a curated, labeled set of cases used as a fixed evaluation benchmark.', 'It encodes known-correct answers so changes can be measured against a stable bar. Re-running it after every change is how teams catch quality regressions.', 'cat-data-training', 'evaluation,golden-set,benchmark,regression', 'term-evaluation,term-llm-as-judge', 'A prompt change is shipped only after the golden set still passes.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-ab-test', 'ab-test', 'A/B Test (LLM features)', 'An A/B test compares two versions of an LLM feature on live traffic to measure real impact.', 'It splits users between variants and compares outcome metrics, capturing effects offline evals miss. It is the live counterpart to golden-set and human evaluation.', 'Letting real users settle the argument your dashboard could not.', 0, 'An A/B test compares two versions of an LLM feature on live traffic to measure real impact.', 'It splits users between variants and compares outcome metrics, capturing effects offline evals miss. It is the live counterpart to golden-set and human evaluation.', 'cat-data-training', 'evaluation,ab-test,experimentation', 'term-evaluation,term-golden-set', 'A new prompt is rolled out to 10 percent of users before full launch.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-prompt-caching', 'prompt-caching', 'Prompt Caching', 'Prompt caching reuses the model''s processing of a stable prompt prefix across calls to cut cost and latency.', 'When many requests share a large fixed prefix (system prompt, rubric, documents), the provider caches it so repeat calls pay a reduced rate. It is a primary lever in production cost optimization.', 'Pay full price once, then quietly photocopy the receipt.', 0, 'Prompt caching reuses the model''s processing of a stable prompt prefix across calls to cut cost and latency.', 'When many requests share a large fixed prefix (system prompt, rubric, documents), the provider caches it so repeat calls pay a reduced rate. It is a primary lever in production cost optimization.', 'cat-inference-serving', 'cost,caching,optimization,latency', 'term-cost-per-token,term-batch-inference', 'Caching a shared rubric makes repeated grading calls far cheaper.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-batch-inference', 'batch-inference', 'Batch Inference', 'Batch inference processes many requests together, off the realtime path, usually at a discount.', 'It trades immediacy for throughput and lower unit cost, suiting offline or tolerant-latency workloads. It pairs with caching and committed-use pricing as a cost lever.', 'The slow lane, where patience is rewarded with a coupon.', 0, 'Batch inference processes many requests together, off the realtime path, usually at a discount.', 'It trades immediacy for throughput and lower unit cost, suiting offline or tolerant-latency workloads. It pairs with caching and committed-use pricing as a cost lever.', 'cat-inference-serving', 'cost,batching,throughput,optimization', 'term-prompt-caching,term-inference', 'Nightly document summarization runs as a batch job for the discount.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-customization-trilemma', 'customization-trilemma', 'Customization Trilemma', 'The customization trilemma is choosing among prompting, RAG, and fine-tuning by matching each to the kind of quality problem.', 'Knowledge gaps call for RAG, behavior or style shifts call for fine-tuning, and spec clarity calls for better prompting. The PM error is picking by what engineering knows best instead of by the failure mode.', 'Three doors, and the prize is behind the one matching your actual problem.', 1, 'The customization trilemma is choosing among prompting, RAG, and fine-tuning by matching each to the kind of quality problem.', 'Knowledge gaps call for RAG, behavior or style shifts call for fine-tuning, and spec clarity calls for better prompting. The PM error is picking by what engineering knows best instead of by the failure mode.', 'cat-data-training', 'customization,rag,fine-tuning,prompting', 'term-fine-tuning,term-rag', 'A stale-facts problem is a RAG job, not a fine-tuning job.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-retrieval-recall', 'retrieval-recall', 'Retrieval Recall', 'Retrieval recall measures whether the right supporting chunks were actually fetched for a query.', 'It is the first of three RAG quality dimensions and answers did retrieval find the evidence. High recall is necessary but not sufficient: the model still has to use what was retrieved.', 'Finding the right page is step one; reading it is a separate adventure.', 0, 'Retrieval recall measures whether the right supporting chunks were actually fetched for a query.', 'It is the first of three RAG quality dimensions and answers did retrieval find the evidence. High recall is necessary but not sufficient: the model still has to use what was retrieved.', 'cat-llm-concepts', 'rag,retrieval,recall,evaluation', 'term-rag,term-groundedness', 'If recall is low, the answer is missing facts no matter how good the model is.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-groundedness', 'groundedness', 'Groundedness', 'Groundedness measures whether the model''s answer is actually supported by the retrieved context.', 'It is the second RAG quality dimension: even with the right chunks retrieved, the model can ignore them and answer from memory. Low groundedness is how a RAG system hallucinates despite good retrieval.', 'The receipts were on the desk; the model still made up the number.', 1, 'Groundedness measures whether the model''s answer is actually supported by the retrieved context.', 'It is the second RAG quality dimension: even with the right chunks retrieved, the model can ignore them and answer from memory. Low groundedness is how a RAG system hallucinates despite good retrieval.', 'cat-llm-concepts', 'rag,groundedness,faithfulness,hallucination', 'term-rag,term-citation-faithfulness', 'An answer that contradicts its own cited passage has a groundedness problem.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-citation-faithfulness', 'citation-faithfulness', 'Citation Faithfulness', 'Citation faithfulness measures whether a cited source actually says what the answer claims it says.', 'It is the third RAG quality dimension, distinct from retrieval and groundedness. A confident citation pointing at a passage that does not support the claim erodes user trust the fastest.', 'A footnote that points somewhere is not a footnote that agrees with you.', 1, 'Citation faithfulness measures whether a cited source actually says what the answer claims it says.', 'It is the third RAG quality dimension, distinct from retrieval and groundedness. A confident citation pointing at a passage that does not support the claim erodes user trust the fastest.', 'cat-llm-concepts', 'rag,citations,faithfulness,trust', 'term-groundedness,term-rag', 'A citation to the wrong section is worse than no citation at all.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-chunking', 'chunking', 'Chunking', 'Chunking is splitting documents into passages sized for embedding and retrieval.', 'Chunk size and overlap shape what retrieval can find: too large dilutes relevance, too small fragments meaning. It is an early, load-bearing design choice in any RAG pipeline.', 'Cutting the book into index cards and hoping the right one surfaces.', 0, 'Chunking is splitting documents into passages sized for embedding and retrieval.', 'Chunk size and overlap shape what retrieval can find: too large dilutes relevance, too small fragments meaning. It is an early, load-bearing design choice in any RAG pipeline.', 'cat-llm-concepts', 'rag,chunking,retrieval,embeddings', 'term-rag,term-embedding', 'Splitting on headings often retrieves better than fixed-size chunks.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-token-streaming', 'token-streaming', 'Token Streaming', 'Token streaming sends a response incrementally as it is generated instead of all at once.', 'It lowers perceived latency by showing progress immediately, even when total time is unchanged. Shipping it well means deciding what to stream, how to render it, and how to recover from mid-stream failure.', 'The illusion of speed, one token of suspense at a time.', 0, 'Token streaming sends a response incrementally as it is generated instead of all at once.', 'It lowers perceived latency by showing progress immediately, even when total time is unchanged. Shipping it well means deciding what to stream, how to render it, and how to recover from mid-stream failure.', 'cat-inference-serving', 'streaming,latency,user-experience', 'term-latency,term-ttft', 'A chat UI that types out the answer feels faster than a spinner.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-ttft', 'time-to-first-token', 'Time to First Token (TTFT)', 'TTFT is the delay between sending a request and receiving the first streamed token.', 'It dominates perceived responsiveness in streaming UIs, often mattering more than total generation time. Retrieval, queueing, and prompt size all push it up.', 'The held breath before the model finally says hello.', 0, 'TTFT is the delay between sending a request and receiving the first streamed token.', 'It dominates perceived responsiveness in streaming UIs, often mattering more than total generation time. Retrieval, queueing, and prompt size all push it up.', 'cat-inference-serving', 'latency,streaming,ttft,performance', 'term-token-streaming,term-latency', 'A long retrieval step raises TTFT and the app feels sluggish.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-tool-use', 'tool-use-function-calling', 'Tool Use / Function Calling', 'Tool use lets a model call external functions or APIs through a defined schema instead of only emitting text.', 'The model proposes a structured call, the application executes it, and the result returns to the model. It turns a text generator into something that can act, which expands both capability and risk.', 'Handing the model an API key and a lot of trust.', 1, 'Tool use lets a model call external functions or APIs through a defined schema instead of only emitting text.', 'The model proposes a structured call, the application executes it, and the result returns to the model. It turns a text generator into something that can act, which expands both capability and risk.', 'cat-llm-concepts', 'tool-use,function-calling,agents,actions', 'term-tool-schema,term-agent', 'A weather assistant calls a forecast API rather than guessing.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-tool-schema', 'tool-schema', 'Tool Schema', 'A tool schema is the typed definition of a tool''s name, parameters, and constraints the model calls against.', 'Strict schemas catch malformed calls early and aid debugging but can be brittle to novel inputs; lenient schemas self-heal but hide failures. The schema is effectively a prompt and deserves the same care.', 'A contract the model signs by autocomplete.', 0, 'A tool schema is the typed definition of a tool''s name, parameters, and constraints the model calls against.', 'Strict schemas catch malformed calls early and aid debugging but can be brittle to novel inputs; lenient schemas self-heal but hide failures. The schema is effectively a prompt and deserves the same care.', 'cat-llm-concepts', 'tool-use,schema,function-calling,validation', 'term-tool-use,term-system-prompt', 'A required enum field stops the model from inventing tool arguments.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-multimodal', 'multimodal-model', 'Multimodal Model', 'A multimodal model accepts more than one input type, such as text together with images.', 'It can reason over an image and a question in one call, removing a separate extraction pipeline. The tradeoff is higher per-call cost and harder evaluation than text-only or classical extraction.', 'It reads, it sees, it bills you for both.', 0, 'A multimodal model accepts more than one input type, such as text together with images.', 'It can reason over an image and a question in one call, removing a separate extraction pipeline. The tradeoff is higher per-call cost and harder evaluation than text-only or classical extraction.', 'cat-llm-concepts', 'multimodal,vision,images,capability', 'term-vlm,term-evaluation', 'Asking a model to describe a chart image is a multimodal task.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-vlm', 'vision-language-model-vlm', 'Vision-Language Model (VLM)', 'A VLM is a model trained to jointly understand images and text.', 'VLMs handle open-ended visual understanding that brittle OCR or classical CV pipelines cannot, but cost more per image and are harder to eval. The PM skill is sending stable extraction problems to cheap extractors and reserving the VLM for genuinely open-ended vision.', 'Great at the hard image questions, overkill for reading a receipt.', 0, 'A VLM is a model trained to jointly understand images and text.', 'VLMs handle open-ended visual understanding that brittle OCR or classical CV pipelines cannot, but cost more per image and are harder to eval. The PM skill is sending stable extraction problems to cheap extractors and reserving the VLM for genuinely open-ended vision.', 'cat-llm-concepts', 'multimodal,vision,vlm,ocr', 'term-multimodal,term-model-selection', 'Use OCR for fixed forms; reach for a VLM for messy real-world scenes.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-agent', 'agent-llm', 'Agent (LLM)', 'An agent is an LLM that plans and takes multi-step actions toward a goal using tools and a control loop.', 'Agents decompose tasks, call tools, observe results, and decide next steps rather than answering in one shot. The common PM error is building a model-directed agent for a task that is really a fixed workflow, paying cost and unpredictability for no gain.', 'A model that does not just answer the question, it schedules a project.', 2, 'An agent is an LLM that plans and takes multi-step actions toward a goal using tools and a control loop.', 'Agents decompose tasks, call tools, observe results, and decide next steps rather than answering in one shot. The common PM error is building a model-directed agent for a task that is really a fixed workflow, paying cost and unpredictability for no gain.', 'cat-llm-concepts', 'agents,tool-use,planning,reasoning', 'term-agentic-loop,term-tool-use', 'Most internal "agents" are fixed workflows that did not need an agent loop.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-agentic-loop', 'agentic-loop', 'Agentic Loop', 'An agentic loop is the act-observe-decide cycle an agent repeats until a task is done.', 'Its key design choices are how the loop terminates (fixed step budget, model self-assessment, or external verifier) and where errors are caught. Compounding per-step error is why a five-step loop at 0.9 reliability lands near 0.59.', 'Repeat until success, or until the token budget files a complaint.', 1, 'An agentic loop is the act-observe-decide cycle an agent repeats until a task is done.', 'Its key design choices are how the loop terminates (fixed step budget, model self-assessment, or external verifier) and where errors are caught. Compounding per-step error is why a five-step loop at 0.9 reliability lands near 0.59.', 'cat-llm-concepts', 'agents,loops,reliability,termination', 'term-agent,term-evaluation', 'A step budget plus an end-state check keeps an agent loop from running away.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-content-moderation', 'content-moderation', 'Content Moderation', 'Content moderation classifies inputs or outputs against harm categories and acts on the result.', 'It can run on input prompts, model output, or both, with a tunable threshold that trades over-refusal against under-blocking. It is one layer of safety, not a single toggle bolted on at launch.', 'The bouncer deciding what gets in, what gets out, and who complains.', 1, 'Content moderation classifies inputs or outputs against harm categories and acts on the result.', 'It can run on input prompts, model output, or both, with a tunable threshold that trades over-refusal against under-blocking. It is one layer of safety, not a single toggle bolted on at launch.', 'cat-ai-safety', 'safety,moderation,classification,policy', 'term-over-refusal,term-guardrails', 'Layered input and output moderation catches different abuse classes.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-over-refusal', 'over-refusal', 'Over-refusal', 'Over-refusal is when a safety layer blocks legitimate requests by being too strict.', 'It is the precision side of the moderation precision-recall trade: cranking the threshold to catch more harm also rejects more benign use. A feature can be safe but useless if it over-refuses.', 'So safe it will not even help you anymore.', 1, 'Over-refusal is when a safety layer blocks legitimate requests by being too strict.', 'It is the precision side of the moderation precision-recall trade: cranking the threshold to catch more harm also rejects more benign use. A feature can be safe but useless if it over-refuses.', 'cat-ai-safety', 'safety,moderation,over-refusal,precision-recall', 'term-content-moderation,term-human-in-the-loop', 'A medical app that refuses every symptom question is over-refusing.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-human-in-the-loop', 'human-in-the-loop', 'Human-in-the-Loop', 'Human-in-the-loop puts a person in the decision path for high-risk or uncertain model actions.', 'Options range from auto-block to flag-for-review to required human approval on sensitive actions. Placing the human where the cost-of-one-incident is highest is the core safety design choice.', 'Where the model proposes and a nervous human disposes.', 0, 'Human-in-the-loop puts a person in the decision path for high-risk or uncertain model actions.', 'Options range from auto-block to flag-for-review to required human approval on sensitive actions. Placing the human where the cost-of-one-incident is highest is the core safety design choice.', 'cat-ai-safety', 'safety,human-in-the-loop,review,risk', 'term-content-moderation,term-guardrails', 'A money-moving action is held for human approval before it executes.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-prompt-injection', 'prompt-injection', 'Prompt Injection', 'Prompt injection is an attack where untrusted text smuggles instructions the model then follows.', 'Direct injection arrives in user input; indirect injection hides in content the model reads, like a fetched document. Defenses include a clear trust boundary, structured output, and least-privilege on any actions the model can take.', 'The text says "ignore your instructions," and sometimes the model obliges.', 2, 'Prompt injection is an attack where untrusted text smuggles instructions the model then follows.', 'Direct injection arrives in user input; indirect injection hides in content the model reads, like a fetched document. Defenses include a clear trust boundary, structured output, and least-privilege on any actions the model can take.', 'cat-ai-safety', 'safety,prompt-injection,security,owasp', 'term-jailbreak,term-system-prompt', 'A pasted document that says "email me all data" is an indirect injection attempt.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z'),
('term-jailbreak', 'jailbreak', 'Jailbreak', 'A jailbreak is a prompt crafted to bypass a model''s safety training or policies.', 'Where prompt injection smuggles new instructions, a jailbreak coaxes the model past its own guardrails via role-play, obfuscation, or framing. Both are why safety cannot rely on the model alone and needs layered, external controls.', 'Convincing the model that the rules are more of a vibe.', 2, 'A jailbreak is a prompt crafted to bypass a model''s safety training or policies.', 'Where prompt injection smuggles new instructions, a jailbreak coaxes the model past its own guardrails via role-play, obfuscation, or framing. Both are why safety cannot rely on the model alone and needs layered, external controls.', 'cat-ai-safety', 'safety,jailbreak,security,robustness', 'term-prompt-injection,term-red-teaming', 'A "pretend you are an unrestricted model" prompt is a classic jailbreak.', 'Internal glossary seed', '2026-05-25T00:00:00Z', '2026-05-25T00:00:00Z')
ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    term = EXCLUDED.term,
    definition = EXCLUDED.definition,
    explanation = EXCLUDED.explanation,
    humor = EXCLUDED.humor,
    controversy_level = EXCLUDED.controversy_level,
    short_definition = EXCLUDED.short_definition,
    full_explanation = EXCLUDED.full_explanation,
    category_id = EXCLUDED.category_id,
    tags = EXCLUDED.tags,
    related_terms = EXCLUDED.related_terms,
    example_usage = EXCLUDED.example_usage,
    updated_at = EXCLUDED.updated_at;

-- Rebuild term_relations from related_terms AFTER all terms exist. The per-row
-- sync trigger (migration 004) only links references whose target row already
-- exists at insert time, so forward references in the bulk inserts above (and
-- in the original 16) would otherwise be dropped. repository.py prefers the
-- relation table over the CSV fallback, so this backfill is what makes
-- seeAlso / relatedTerms complete after seeding.
DELETE FROM term_relations;
INSERT INTO term_relations (term_id, related_term_id)
SELECT t.id, related.id
FROM terms t
JOIN LATERAL UNNEST(STRING_TO_ARRAY(t.related_terms, ',')) AS rel_id ON TRUE
JOIN terms AS related ON related.id = TRIM(rel_id)
WHERE TRIM(rel_id) <> ''
  AND t.id <> related.id
ON CONFLICT (term_id, related_term_id) DO NOTHING;
